import{_ as s,o as a,c as i,a4 as o}from"./chunks/framework.C5YtifhL.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"framework/installation.md","filePath":"framework/installation.md","lastUpdated":1781601194000}'),t={name:"framework/installation.md"};function n(l,e,r,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p><code>lo</code> est le framework RedM monolithique de Last Country : une ressource unique qui agrège le noyau (sessions, comptes, personnages) et ses systèmes sous forme de <strong>classes et services globaux nommés</strong> (ex. <code>Players</code>, <code>Inventory</code>, <code>Logger</code>, <code>Jail</code>, <code>Doors</code>). Cette page décrit les prérequis serveur, l&#39;ordre de démarrage dans <code>server.cfg</code>, le schéma de base de données auto-géré, et le workflow de développement au quotidien.</p><div class="danger custom-block"><p class="custom-block-title">Cible RedM uniquement</p><p><code>lo</code> cible <strong>RedM / <code>rdr3</code> exclusivement</strong>. Le <code>fxmanifest.lua</code> déclare <code>game &#39;rdr3&#39;</code> et un <code>rdr3_warning</code>. Ne l&#39;utilisez jamais sur un serveur FiveM.</p></div><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><p>Avant de démarrer <code>lo</code>, votre serveur doit remplir les conditions suivantes, dérivées directement du <code>fxmanifest.lua</code> :</p><table tabindex="0"><thead><tr><th>Prérequis</th><th>Détail</th><th>Source</th></tr></thead><tbody><tr><td>FXServer</td><td>Build serveur <strong>6231 minimum</strong> (<code>/server:6231</code>)</td><td><code>dependencies</code></td></tr><tr><td>OneSync</td><td><strong>Activé</strong> (<code>/onesync</code>)</td><td><code>dependencies</code></td></tr><tr><td>oxmysql</td><td>Ressource <code>oxmysql</code> démarrée avant <code>lo</code></td><td><code>dependencies</code> + <code>@oxmysql/lib/MySQL.lua</code></td></tr><tr><td>jo_libs</td><td>Fondation obligatoire (chargée via <code>@jo_libs/init.lua</code>)</td><td><code>shared_script</code></td></tr><tr><td>Base MySQL/MariaDB</td><td>Une base accessible par oxmysql (le schéma est créé automatiquement)</td><td><code>jo.database</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">OneSync est obligatoire</p><p>Le framework est serveur-autoritaire et s&#39;appuie sur les routing buckets (sélection de personnage et créateur isolés dans un bucket dédié) ainsi que sur les state bags répliqués (<code>userId</code>, <code>charId</code>, <code>citizenid</code>, <code>job</code>, <code>gang</code>...). OneSync doit être activé pour que ces mécanismes fonctionnent.</p></div><h3 id="jo-libs" tabindex="-1">jo_libs <a class="header-anchor" href="#jo-libs" aria-label="Permalink to &quot;jo_libs&quot;">​</a></h3><p><code>jo_libs</code> (JollyLib) est la fondation obligatoire de <code>lo</code> : toutes les primitives passent par elle (<code>jo.callback</code>, <code>jo.database</code>, <code>jo.menu</code>, <code>jo.input</code>, <code>jo.player</code>, <code>jo.component</code>, <code>jo.notif</code>, etc.). Le manifeste de <code>lo</code> charge <code>@jo_libs/init.lua</code> en tête des <code>shared_script</code> et active les modules dont il a besoin via les directives <code>jo_lib</code> (player, component, ped-texture, database, menu, input, prompt-nui, dataview, notification, callback, entity, hook, table, utils, blip, game-events, emit, waiter, debugger, nui, animation, raw-keys, prompt).</p><p><code>jo_libs</code> doit être présent et démarré avant <code>lo</code>.</p><h2 id="lo-fournit-provide-rsg-core-et-rsg-inventory" tabindex="-1">lo fournit (provide) rsg-core et rsg-inventory <a class="header-anchor" href="#lo-fournit-provide-rsg-core-et-rsg-inventory" aria-label="Permalink to &quot;lo fournit (provide) rsg-core et rsg-inventory&quot;">​</a></h2><p>Le <code>fxmanifest.lua</code> de <code>lo</code> déclare :</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">provide</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;rsg-core&#39;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">provide</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;rsg-inventory&#39;</span></span></code></pre></div><p>Cela signifie que <code>lo</code> <strong>se substitue</strong> à ces deux ressources : le bridge de <code>lo</code> émet les events miroirs attendus (<code>RSGCore:*</code>) et expose l&#39;objet core via <code>exports[&#39;rsg-core&#39;]:GetCoreObject()</code>. Les ressources tierces qui dépendent de <code>rsg-core</code> ou <code>rsg-inventory</code> continuent donc de fonctionner sans les ressources d&#39;origine.</p><div class="info custom-block"><p class="custom-block-title">Pas de gestion météo dans le core</p><p><code>lo</code> ne fournit <strong>pas</strong> <code>weathersync</code> : la gestion de la météo et du temps a été retirée du core. Elle est désormais déléguée à une ressource externe dédiée (voir <a href="./modules/weather">Météo &amp; Temps</a>).</p></div><div class="danger custom-block"><p class="custom-block-title">Ne JAMAIS démarrer rsg-core</p><p>Comme <code>lo</code> déclare déjà <code>provide &#39;rsg-core&#39;</code>, lancer <code>rsg-core</code> (ou <code>rsg-inventory</code>) <strong>en parallèle</strong> casse le boot et provoque une double détection du framework. Ces ressources ne doivent <strong>jamais</strong> figurer dans votre <code>server.cfg</code>. Du code interne à <code>lo</code>, on ne passe d&#39;ailleurs jamais par <code>exports[&#39;rsg-core&#39;]</code> ou <code>jo.framework</code> : tout passe directement par les globaux nommés du framework (<code>PlayerService</code>, <code>Inventory</code>, <code>Net</code>, <code>Commands</code>…).</p></div><h2 id="ordre-de-demarrage-dans-server-cfg" tabindex="-1">Ordre de démarrage dans server.cfg <a class="header-anchor" href="#ordre-de-demarrage-dans-server-cfg" aria-label="Permalink to &quot;Ordre de démarrage dans server.cfg&quot;">​</a></h2><p>L&#39;ordre est important car <code>lo</code> dépend de <code>oxmysql</code>, de <code>sessionmanager-rdr3</code> et de <code>jo_libs</code>, charge son NUI depuis <code>lo_ui</code>, et parce que toute ressource externe qui inclut un fichier <code>@lo/...</code> (par exemple <code>@lo/bridge/ac_protect.lua</code>) a besoin que <code>lo</code> ait démarré <strong>avant</strong> elle pour que l&#39;include se résolve.</p><p>Ordre recommandé :</p><ol><li><code>oxmysql</code> (la connexion DB doit être prête avant le schéma de <code>lo</code>).</li><li><code>sessionmanager-rdr3</code> (gestionnaire de sessions RedM).</li><li><code>jo_libs</code> (fondation chargée par <code>lo</code>).</li><li><code>lo_ui</code> (l&#39;interface React, servie par le frame NUI de <code>lo</code>).</li><li><code>lo</code> (le framework, qui fournit <code>rsg-core</code> / <code>rsg-inventory</code>).</li><li>Les ressources tierces (<code>chat</code>, anticheat, scripts métier comme <code>lo_jobscreator</code>, ressources externes).</li></ol><h3 id="exemple-de-bloc-server-cfg" tabindex="-1">Exemple de bloc server.cfg <a class="header-anchor" href="#exemple-de-bloc-server-cfg" aria-label="Permalink to &quot;Exemple de bloc server.cfg&quot;">​</a></h3><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Build serveur et OneSync (prérequis lo)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sv_enforceGameBuild 1491</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">onesync on</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Base de données</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ensure oxmysql</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Gestionnaire de sessions et fondation</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ensure sessionmanager-rdr3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ensure jo_libs</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Interface (servie par le frame NUI de lo)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ensure lo_ui</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. Framework lo</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    fournit rsg-core / rsg-inventory</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    NE JAMAIS ajouter &quot;ensure rsg-core&quot; ici.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ensure lo</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 5. Ressources tierces</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ensure chat</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ensure lo_ac</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ensure lo_jobscreator</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ensure &lt;vos scripts metier&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Connexion MySQL (oxmysql)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">set mysql_connection_string </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mysql://user:password@localhost/lastcountry?charset=utf8mb4&quot;</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Si une ressource externe inclut <code>@lo/bridge/ac_protect.lua</code> (protection anticheat de ses entités), elle doit impérativement être démarrée <strong>après</strong> <code>lo</code> dans le <code>server.cfg</code> pour que l&#39;include <code>@lo/...</code> se résolve.</p></div><h2 id="schema-de-base-de-donnees-automatique" tabindex="-1">Schéma de base de données automatique <a class="header-anchor" href="#schema-de-base-de-donnees-automatique" aria-label="Permalink to &quot;Schéma de base de données automatique&quot;">​</a></h2><p><code>lo</code> <strong>ne fournit aucun fichier <code>.sql</code> à importer manuellement</strong>. Le schéma est créé et migré automatiquement au démarrage via <code>jo.database</code>.</p><ul><li>Toute table et toute colonne sont déclarées dans <code>database/server/schema.lua</code> exclusivement, via <code>jo.database.addTable</code> / <code>jo.database.addColumn</code>.</li><li>Au boot, <code>jo.database</code> crée les tables manquantes et ajoute les colonnes manquantes : un serveur neuf comme une base existante convergent vers le schéma attendu sans intervention.</li><li>La suppression de personnage est un soft delete (<code>deleted_at</code>), jamais une suppression physique.</li></ul><p>Tables principales gérées automatiquement :</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">users      (id, discord </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UNIQUE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, license </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UNIQUE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, favorite_char_id, banned, created_at)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">characters (id, user_id FK, citizenid </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UNIQUE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, slot,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            charinfo </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">money</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, job </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, gang </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            metadata </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, position </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            skin LONGTEXT, clothes LONGTEXT,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            deleted_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TIMESTAMP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            created_at, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UNIQUE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(user_id, slot))</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La seule condition côté DB est qu&#39;oxmysql puisse se connecter à une base existante. Le reste (création des tables, ajout des colonnes) est pris en charge par <code>lo</code> au démarrage.</p></div><h2 id="workflow-de-developpement" tabindex="-1">Workflow de développement <a class="header-anchor" href="#workflow-de-developpement" aria-label="Permalink to &quot;Workflow de développement&quot;">​</a></h2><p><code>lo</code> est du Lua interprété côté serveur : <strong>pas de build Lua, pas d&#39;interpréteur local</strong>. La boucle de validation est rapide.</p><h3 id="restart-a-chaud" tabindex="-1">Restart à chaud <a class="header-anchor" href="#restart-a-chaud" aria-label="Permalink to &quot;Restart à chaud&quot;">​</a></h3><p>Pour appliquer une modification du code Lua, redémarrez la ressource depuis la console serveur :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lo</span></span></code></pre></div><p>Le restart en développement est conçu pour être transparent : au <code>onResourceStop</code>, tous les joueurs actifs sont sauvegardés et leur <code>lastCharId</code> conservé dans les state bags (qui survivent au restart de la ressource) ; au <code>onResourceStart</code>, chaque joueur connecté est reconstruit (session relue, re-login automatique sur son dernier personnage) puis respawné en place via <code>Spawner.spawn{ reason = &#39;restart&#39; }</code>. Résultat : tout le monde est rechargé sans écran de sélection ni téléportation, skin réappliqué.</p><div class="tip custom-block"><p class="custom-block-title">Avant de livrer</p><p>Aucun interpréteur local n&#39;est disponible : validez toujours par <code>restart lo</code> + lecture de la console serveur + test côté client (F8). Vérifiez l&#39;équilibre syntaxique (parenthèses, <code>end</code>, accolades) avant de redémarrer.</p></div><h3 id="console-client-f8-et-logs" tabindex="-1">Console client (F8) et logs <a class="header-anchor" href="#console-client-f8-et-logs" aria-label="Permalink to &quot;Console client (F8) et logs&quot;">​</a></h3><ul><li>Ouvrez la console client avec <strong>F8</strong> en jeu pour observer les erreurs et messages côté client.</li><li>Côté serveur, surveillez la console qui trace tout le cycle de vie de la session (<code>session:transition</code>) et les logs des modules.</li></ul><p>Le logger est piloté par catégorie via le global <code>Logger</code> :</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Logger</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">info</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Catégorie&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;message...&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Les catégories sont activables/désactivables par la table <code>Config.Debug</code> et, à chaud, par la commande :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/debug</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Catégori</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="front-lo-ui" tabindex="-1">Front (lo_ui) <a class="header-anchor" href="#front-lo-ui" aria-label="Permalink to &quot;Front (lo_ui)&quot;">​</a></h3><p>Le front React vit dans une ressource séparée, <code>lo_ui</code>. Après une modification de l&#39;interface :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> resources/[ui]/lo_ui/web</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Puis, depuis la console serveur, redémarrez uniquement l&#39;interface (inutile de redémarrer <code>lo</code>) :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lo_ui</span></span></code></pre></div><h3 id="autocompletion-vscode" tabindex="-1">Autocomplétion VSCode <a class="header-anchor" href="#autocompletion-vscode" aria-label="Permalink to &quot;Autocomplétion VSCode&quot;">​</a></h3><p>Pour développer contre l&#39;API du framework, installez l&#39;extension VSCode <code>communityox.cfxlua-vscode-cox</code> (natives RedM). Les définitions de l&#39;API publique de <code>lo</code> (les globaux nommés : <code>Players</code>, <code>PlayerService</code>, <code>Inventory</code>, <code>Net</code>, <code>Commands</code>, <code>Logger</code>, <code>Skin</code>…) sont fournies par <code>types/core.lua</code> (annotations LuaLS <code>---@meta</code>), à tenir à jour à chaque évolution d&#39;API.</p>`,49)])])}const k=s(t,[["render",n]]);export{u as __pageData,k as default};
